#include <array>
#include <cstddef>
#include <iostream>

int main()
{
    std::array<int, 5> arr{};

    for (std::size_t i{ 0 }; i < arr.size(); ++i)
        std::cin >> arr[i];

    std::cout << "Size: " << arr.size() << '\n';
    std::cout << "First: " << arr[0] << '\n';
    std::cout << "Last: " << arr.at(arr.size() - 1) << '\n';
    std::cout << "Middle: " << arr.at(2) << '\n';

    return 0;
}

