#include <array>
#include <cstddef>
#include <iostream>
#include <stdexcept>

int main()
{
    std::array<int, 6> arr{};

    for (std::size_t i{ 0 }; i < arr.size(); ++i)
        std::cin >> arr[i];

    int index{};
    std::cin >> index;

    std::cout << "Size: " << arr.size() << '\n';

    try
    {
        std::cout << "Value: " << arr.at(static_cast<std::size_t>(index)) << '\n';
    }
    catch (const std::out_of_range&)
    {
        std::cout << "Error: index out of range" << '\n';
    }

    return 0;
}
